import { describe, it, expect } from 'vitest';
import { convertMigration, extractKeptTSQL } from '../MigrationConverter.js';

const codegenItem = (title: string, body: string) =>
  [
    `/* ${title} */`,
    '-----------------------------------------------------------------',
    '-- This was generated by the MemberJunction CodeGen tool.',
    '-----------------------------------------------------------------',
    body,
  ].join('\n');

describe('convertMigration', () => {
  it('transpiles regular DDL and drops the CodeGen block', () => {
    const sql = [
      'CREATE TABLE [__mj].[Widget] ( [ID] UNIQUEIDENTIFIER NOT NULL );',
      codegenItem('spCreate SQL for Widget', 'CREATE PROCEDURE [__mj].[spCreateWidget] AS BEGIN SELECT 1 END'),
    ].join('\n');

    const r = convertMigration(sql, 'V_Widget.sql');
    expect(r.status).toBe('converted');
    // CodeGen sproc must not appear in the PG output — it is regenerated, not translated.
    expect(r.pgSQL).not.toContain('spCreateWidget');
    expect(r.droppedCodeGenLines).toBeGreaterThan(0);
    // Regular DDL was transpiled (brackets removed → PG identifiers).
    expect(r.pgSQL).toContain('Widget');
    expect(r.notes.some((n) => n.includes('regenerated natively'))).toBe(true);
  });

  it('flags a file with hand-written procedural SQL as needs-hand-authoring', () => {
    const sql = [
      'CREATE TABLE __mj.Job (ID INT);',
      'GO',
      'CREATE OR ALTER PROCEDURE __mj.spClaimJob AS BEGIN UPDATE __mj.Job SET X=1; END;',
    ].join('\n');
    const r = convertMigration(sql, 'Scheduling_Engine_Atomic_Sprocs.sql');
    expect(r.status).toBe('needs-hand-authoring');
    expect(r.pgSQL).toContain('NEEDS HAND-AUTHORING');
    expect(r.notes[0]).toContain('hand-written procedural SQL');
  });

  it('treats a pure mj-sync Metadata_Sync file as reseed-or-regen-only (no DDL emitted)', () => {
    const sql = [
      '-- SQL Logging Session',
      '-- Description: MetadataSync push operation',
      'DECLARE @Name_da319a9d NVARCHAR(50);',
      "SET @Name_da319a9d = 'GPT';",
      'EXEC __mj.spCreateAIModel @Name = @Name_da319a9d;',
    ].join('\n');
    const r = convertMigration(sql, 'V_Metadata_Sync.sql');
    expect(r.status).toBe('reseed-or-regen-only');
    expect(r.pgSQL).toContain('mj sync push');
    // No spCreate call carried into the PG output — it is re-seeded, not transpiled.
    expect(r.pgSQL).not.toContain('spCreateAIModel');
  });

  it('keeps an mj-sync file as reseed even when it contains incidental data DML (not schema DDL)', () => {
    // Regression: a 964k-line Metadata_Sync file was mis-routed to "converted"
    // because an INSERT/UPDATE matched the DDL regex. Data DML in an mj-sync file
    // is the metadata seed itself — reproduced by `mj sync push`, never transpiled.
    const sql = [
      '-- SQL Logging Session',
      '-- Description: MetadataSync push operation',
      'DECLARE @Name_da319a9d NVARCHAR(50);',
      'UPDATE __mj.AIModel SET Name = @Name_da319a9d WHERE ID = 1;',
      'EXEC __mj.spCreateAIModel @Name = @Name_da319a9d;',
    ].join('\n');
    const r = convertMigration(sql, 'V202604271430__Metadata_Sync.sql');
    expect(r.status).toBe('reseed-or-regen-only');
    expect(r.pgSQL).not.toContain('spCreateAIModel');
  });

  it('transpiles a Backfill_* data migration (data DML, no mj-sync fingerprints)', () => {
    const sql = "UPDATE __mj.UserView SET ViewTypeID = 'x' WHERE ViewTypeID IS NULL;";
    const r = convertMigration(sql, 'V_Backfill_UserView_ViewTypeID.sql');
    expect(r.status).toBe('converted');
  });

  it('treats a pure CodeGen-only file as reseed-or-regen-only', () => {
    const sql = [
      '-- regen only',
      codegenItem('spDelete SQL for Foo', 'CREATE PROCEDURE __mj.spDeleteFoo AS BEGIN DELETE FROM __mj.Foo END'),
    ].join('\n');
    const r = convertMigration(sql, 'spDelete_Force_Regen.sql');
    expect(r.status).toBe('reseed-or-regen-only');
    expect(r.pgSQL).not.toContain('spDeleteFoo');
    expect(r.pgSQL).toContain('mj codegen');
  });
});

describe('extractKeptTSQL — entity-registration recovery from the CodeGen block', () => {
  // A feature migration whose CodeGen output sits below an explicit `-- CODE GEN RUN` banner.
  // The whole post-banner block is routed to codeGenBlock and dropped — but the entity
  // REGISTRATION rows (Entity / EntityField / …) have no schema-introspection source on PG,
  // so they must be recovered. Base-table seed rows and generated views/sprocs/grants stay dropped.
  const bannered = [
    'CREATE TABLE [${flyway:defaultSchema}].[Widget] ( [ID] UNIQUEIDENTIFIER NOT NULL );',
    'GO',
    '-- CODE GEN RUN',
    '/* SQL generated to create new entity MJ: Widgets */',
    "INSERT INTO [${flyway:defaultSchema}].[Entity] ([ID],[Name],[BaseView],[SchemaName]) " +
      "VALUES ('aaaa', 'MJ: Widgets', 'vwWidgets', '${flyway:defaultSchema}');",
    'GO',
    '/* SQL generated to add new entity MJ: Widgets to application */',
    "INSERT INTO [${flyway:defaultSchema}].[ApplicationEntity] ([ID],[EntityID]) VALUES ('bbbb','aaaa');",
    'GO',
    '/* SQL text to insert new entity field */',
    "IF NOT EXISTS (SELECT 1 FROM [${flyway:defaultSchema}].[EntityField] WHERE ID = 'cccc') BEGIN " +
      "INSERT INTO [${flyway:defaultSchema}].[EntityField] ([ID],[EntityID],[Name]) VALUES ('cccc','aaaa','ID'); END",
    'GO',
    '/* base-table seed row — NOT a registration row, must stay dropped */',
    "INSERT INTO [${flyway:defaultSchema}].[Widget] ([ID]) VALUES ('dddd');",
    'GO',
    '/* generated view — regenerated by mj codegen, must stay dropped */',
    'CREATE VIEW [${flyway:defaultSchema}].[vwWidgets] AS SELECT * FROM [${flyway:defaultSchema}].[Widget];',
    'GO',
    'GRANT SELECT ON [${flyway:defaultSchema}].[vwWidgets] TO [cdp_UI];',
  ].join('\n');

  it('recovers Entity / ApplicationEntity / EntityField registration rows', () => {
    const kept = extractKeptTSQL(bannered, 'V_Widgets_Feature.sql');
    expect(kept.status).toBe('converted');
    expect(kept.tsql).toContain("'MJ: Widgets'");
    expect(kept.tsql).toContain('[ApplicationEntity]');
    expect(kept.tsql).toContain('[EntityField]');
  });

  it('does NOT recover base-table seed rows, generated views, or grants', () => {
    const kept = extractKeptTSQL(bannered, 'V_Widgets_Feature.sql');
    // The base-table seed INSERT (INSERT INTO Widget (...)) must not be recovered.
    expect(kept.tsql).not.toMatch(/INSERT\s+INTO\s+\[\$\{flyway:defaultSchema\}\]\.\[Widget\]\s*\(/i);
    expect(kept.tsql).not.toContain('CREATE VIEW');
    expect(kept.tsql).not.toContain('GRANT SELECT');
  });

  it('truncates a registration batch that bundles a view regeneration without a GO separator', () => {
    // CodeGen emits the EntityField inserts and the `----- BASE VIEW FOR ENTITY …` /
    // `IF OBJECT_ID(...,'V') DROP VIEW … CREATE VIEW …` block back-to-back in ONE GO-batch.
    // The registration prefix must be kept; the trailing generated view (which `mj codegen`
    // rebuilds, and whose DROP VIEW would fail on PG when dependents exist) must be dropped.
    const sql = [
      'CREATE TABLE [${flyway:defaultSchema}].[Thing] ( [ID] UNIQUEIDENTIFIER NOT NULL );',
      'GO',
      '-- CODE GEN RUN',
      '/* SQL text to insert new entity field */',
      "IF NOT EXISTS (SELECT 1 FROM [${flyway:defaultSchema}].[EntityField] WHERE ID = 'ffff') BEGIN " +
        "INSERT INTO [${flyway:defaultSchema}].[EntityField] ([ID],[Name]) VALUES ('ffff','Title'); END",
      '------------------------------------------------------------',
      '----- BASE VIEW FOR ENTITY:      MJ: Things',
      '------------------------------------------------------------',
      "IF OBJECT_ID('[${flyway:defaultSchema}].[vwThings]', 'V') IS NOT NULL",
      'DROP VIEW [${flyway:defaultSchema}].[vwThings];',
      'GO',
      'CREATE VIEW [${flyway:defaultSchema}].[vwThings] AS SELECT * FROM [${flyway:defaultSchema}].[Thing];',
    ].join('\n');
    const kept = extractKeptTSQL(sql, 'V_Things_Feature.sql');
    expect(kept.tsql).toContain('[EntityField]');
    expect(kept.tsql).not.toMatch(/DROP\s+VIEW/i);
    expect(kept.tsql).not.toMatch(/CREATE\s+VIEW/i);
    expect(kept.tsql).not.toContain('OBJECT_ID');
  });

  it('leaves a no-banner feature file (registration rows already inline) unchanged in spirit', () => {
    // No `-- CODE GEN RUN` banner: the splitter keeps the registration INSERTs inline, so the
    // recovery is a no-op (codeGenBlock is empty) but the rows still survive.
    const noBanner = [
      'CREATE TABLE [${flyway:defaultSchema}].[Gadget] ( [ID] UNIQUEIDENTIFIER NOT NULL );',
      'GO',
      "INSERT INTO [${flyway:defaultSchema}].[Entity] ([ID],[Name]) VALUES ('eeee','MJ: Gadgets');",
    ].join('\n');
    const kept = extractKeptTSQL(noBanner, 'V_Gadgets_Feature.sql');
    expect(kept.tsql).toContain("'MJ: Gadgets'");
  });
});
